    ) {
        let paths: Vec<PathBuf> = workspaces.iter().map(PathBuf::from).collect();
        let cache = WorkspaceCache::new(paths);

        for other in &others {
            // This tests the full contains() path (bloom + exact)
            // May have false positives in bloom, but exact set rejects
            let path = PathBuf::from(other);
            // Verify through exact set (should always be false)
            prop_assert!(!cache.exact.contains(&path));
        }
    }
